{
  "name": "Bollywood Word Singing Game",
  "description": "An interactive Antakshari-style game where you sing Bollywood songs based on random or selected words. Challenge your memory and musical knowledge with over 100 iconic Hindi words."
}

export enum Difficulty {
  Easy = 'Easy',
  Medium = 'Medium',
  Hard = 'Hard'
}

export enum Category {
  Love = 'Love',
  Emotion = 'Emotion',
  Nature = 'Nature',
  Life = 'Life',
  Party = 'Party',
  Classic = 'Classic'
}

export interface BollywoodWord {
  id: string;
  word: string;
  englishMeaning: string;
  songs: string[];
  difficulty: Difficulty;
  category: Category;
}

export type FilterState = {
  difficulty: Difficulty | 'All';
  category: Category | 'All';
  search: string;
};

import React from 'react';
import { BollywoodWord, Difficulty } from '../types';

interface WordCardProps {
  item: BollywoodWord;
  onClick: (item: BollywoodWord) => void;
}

const getDifficultyColor = (diff: Difficulty) => {
  switch (diff) {
    case Difficulty.Easy: return 'bg-green-500/20 text-green-400 border-green-500/30';
    case Difficulty.Medium: return 'bg-yellow-500/20 text-yellow-400 border-yellow-500/30';
    case Difficulty.Hard: return 'bg-red-500/20 text-red-400 border-red-500/30';
    default: return 'bg-gray-500/20 text-gray-400 border-gray-500/30';
  }
};

export const WordCard: React.FC<WordCardProps> = ({ item, onClick }) => {
  return (
    <button
      onClick={() => onClick(item)}
      className="group relative bg-slate-800/50 hover:bg-slate-700/50 border border-slate-700/50 rounded-xl p-4 transition-all duration-300 transform hover:-translate-y-1 hover:shadow-xl hover:shadow-amber-500/10 active:scale-95 text-left w-full"
    >
      <div className="flex justify-between items-start mb-2">
        <span className={`text-[10px] uppercase font-bold px-2 py-0.5 rounded-full border ${getDifficultyColor(item.difficulty)}`}>
          {item.difficulty}
        </span>
        <span className="text-[10px] text-slate-400 font-medium italic">
          {item.category}
        </span>
      </div>
      <h3 className="hindi-font text-2xl font-bold text-amber-100 mb-1 group-hover:text-amber-400 transition-colors">
        {item.word}
      </h3>
      <p className="text-slate-400 text-sm font-light">
        {item.englishMeaning}
      </p>

      {/* Decorative gradient element */}
      <div className="absolute bottom-0 left-0 h-1 w-0 bg-gradient-to-r from-amber-500 to-orange-500 group-hover:w-full transition-all duration-500 rounded-b-xl" />
    </button>
  );
};

import React, { useState, useEffect } from 'react';

interface TimerProps {
  duration: number;
  onComplete: () => void;
  isActive: boolean;
}

export const Timer: React.FC<TimerProps> = ({ duration, onComplete, isActive }) => {
  const [timeLeft, setTimeLeft] = useState(duration);

  useEffect(() => {
    let timer: any;
    if (isActive && timeLeft > 0) {
      timer = setInterval(() => {
        setTimeLeft((prev) => prev - 1);
      }, 1000);
    } else if (timeLeft === 0) {
      onComplete();
    }
    return () => clearInterval(timer);
  }, [isActive, timeLeft, onComplete]);

  // Reset timer if duration changes (when a new word is picked)
  useEffect(() => {
    setTimeLeft(duration);
  }, [duration]);

  const percentage = (timeLeft / duration) * 100;

  return (
    <div className="relative flex flex-col items-center justify-center">
      <div className="w-16 h-16 rounded-full border-4 border-slate-700 flex items-center justify-center overflow-hidden">
        <div 
          className="absolute bottom-0 w-full bg-amber-500/30 transition-all duration-1000 ease-linear"
          style={{ height: `${percentage}%` }}
        />
        <span className="relative z-10 text-2xl font-bold text-amber-500">{timeLeft}</span>
      </div>
      <p className="mt-2 text-xs text-slate-400 font-medium">SING NOW!</p>
    </div>
  );
};

import React, { useState, useMemo, useEffect, useCallback } from 'react';
