import { BollywoodWord, Difficulty, Category, FilterState } from './types';
import { WordCard } from './components/WordCard';
import { Timer } from './components/Timer';

// Add simple confetti effect on success
const triggerConfetti = () => {
  // We can't easily add canvas-confetti via script here, but we can simulate excitement with a temporary flash or similar
  console.log("Hurray! Confetti Time!");
};

const App: React.FC = () => {
