import React, { useState, useEffect } from 'react';

interface TimerProps {
  duration: number;
  onComplete: () => void;
  onTick?: (timeLeft: number) => void;
  isActive: boolean;
}

export const Timer: React.FC<TimerProps> = ({ duration, onComplete, onTick, isActive }) => {
  const [timeLeft, setTimeLeft] = useState(duration);

  useEffect(() => {
    let timer: any;
    if (isActive && timeLeft > 0) {
      timer = setInterval(() => {
        setTimeLeft((prev) => {
          const next = prev - 1;
          if (onTick) {
            onTick(next);
          }
          return next;
        });
      }, 1000);
    } else if (timeLeft === 0) {
      onComplete();
    }
    return () => clearInterval(timer);
  }, [isActive, timeLeft, onComplete, onTick]);

  // Reset timer if duration changes (when a new word is picked)
  useEffect(() => {
    setTimeLeft(duration);
  }, [duration]);

  const percentage = (timeLeft / duration) * 100;

  return (
    <div className="relative flex flex-col items-center justify-center">
      <div className="w-24 h-24 rounded-full border-4 border-slate-700 flex items-center justify-center overflow-hidden">
        <div 
          className={`absolute bottom-0 w-full transition-all duration-1000 ease-linear ${
            timeLeft <= 10 ? 'bg-rose-500/40' : 'bg-amber-500/30'
          }`}
          style={{ height: `${percentage}%` }}
        />
        <span className={`relative z-10 text-4xl font-bold transition-colors ${
          timeLeft <= 10 ? 'text-rose-500 animate-pulse' : 'text-amber-500'
        }`}>
          {timeLeft}
        </span>
      </div>
      <p className={`mt-3 text-xs font-bold tracking-widest ${
        timeLeft <= 10 ? 'text-rose-500 animate-bounce' : 'text-slate-400'
      }`}>
        {timeLeft <= 10 ? 'HURRY UP!' : 'SING NOW!'}
      </p>
    </div>
  );
};

