      `}} />

      <p className={`mt-2 text-[10px] font-black tracking-widest uppercase transition-colors ${
        timeLeft <= 5 ? 'text-rose-500 animate-bounce' : 'text-amber-500'
      }`}>
        {timeLeft <= 5 ? 'SING NOW!' : 'CLOCK IS TICKING'}
