import React, { useState, useEffect } from 'react';

interface TimerProps {
  duration: number;
  onComplete: () => void;
  onTick?: (timeLeft: number) => void;
  isActive: boolean;
}

export const Timer: React.FC<TimerProps> = ({ duration, onComplete, onTick, isActive }) => {
  const [timeLeft, setTimeLeft] = useState(duration);

  useEffect(() => {
    let timer: any;
    if (isActive && timeLeft > 0) {
      timer = setInterval(() => {
        setTimeLeft((prev) => {
          const next = prev - 1;
          if (onTick) onTick(next);
          return next;
        });
      }, 1000);
    } else if (timeLeft === 0) {
      onComplete();
    }
    return () => clearInterval(timer);
  }, [isActive, timeLeft, onComplete, onTick]);

  useEffect(() => {
    setTimeLeft(duration);
  }, [duration]);

  const topRatio = timeLeft / duration;
  const bottomRatio = 1 - topRatio;

  return (
    <div className="relative flex flex-col items-center justify-center scale-100 -my-2">
      <div className="relative w-32 h-40">
        <svg viewBox="0 0 100 140" className="w-full h-full drop-shadow-[0_0_15px_rgba(212,175,55,0.3)]">
          <defs>
            <clipPath id="top-bulb">
              <rect x="0" y={10 + (60 * (1 - topRatio))} width="100" height="60" />
            </clipPath>
            <clipPath id="bottom-bulb">
              <rect x="0" y={130 - (60 * bottomRatio)} width="100" height="60" />
            </clipPath>
            <linearGradient id="sand-gradient" x1="0" y1="0" x2="0" y2="1">
              <stop offset="0%" stopColor="#fde68a" />
              <stop offset="100%" stopColor="#d4af37" />
            </linearGradient>
          </defs>

          {/* Glass Outlines */}
          <path d="M 20 10 H 80 C 80 10, 80 20, 75 30 L 55 65 C 52 70, 48 70, 45 65 L 25 30 C 20 20, 20 10, 20 10 Z" fill="rgba(255,255,255,0.02)" stroke="rgba(255,255,255,0.1)" strokeWidth="1" />
          <path d="M 25 110 L 45 75 C 48 70, 52 70, 55 75 L 75 110 C 80 120, 80 130, 80 130 H 20 C 20 130, 20 120, 25 110 Z" fill="rgba(255,255,255,0.02)" stroke="rgba(255,255,255,0.1)" strokeWidth="1" />

          {/* Sand */}
          <path d="M 20 10 H 80 L 50 70 Z" fill="url(#sand-gradient)" clipPath="url(#top-bulb)" className="transition-all duration-1000 ease-linear" />
          <path d="M 20 130 H 80 L 50 70 Z" fill="url(#sand-gradient)" clipPath="url(#bottom-bulb)" className="transition-all duration-1000 ease-linear" />

          {timeLeft > 0 && isActive && (
            <line x1="50" y1="65" x2="50" y2="125" stroke="#d4af37" strokeWidth="1.5" strokeDasharray="3 3" className="animate-sand-flow" />
          )}

          <rect x="15" y="5" width="70" height="4" rx="2" fill="#d4af37" opacity="0.8" />
          <rect x="15" y="131" width="70" height="4" rx="2" fill="#d4af37" opacity="0.8" />
        </svg>

        <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
          <span className={`text-4xl font-black heading-font transition-all ${timeLeft <= 5 ? 'text-rose-500 scale-125 animate-pulse' : 'text-amber-500'}`}>
            {timeLeft}
          </span>
        </div>
      </div>

      <style dangerouslySetInnerHTML={{ __html: `
        @keyframes sand-flow {
          from { stroke-dashoffset: 0; }
          to { stroke-dashoffset: -12; }
        }
        .animate-sand-flow {
          animation: sand-flow 0.4s linear infinite;
        }
      `}} />

      <p className={`mt-4 text-[9px] font-black tracking-[0.3em] uppercase transition-colors ${timeLeft <= 5 ? 'text-rose-500 animate-bounce' : 'text-amber-500/60'}`}>
        {timeLeft <= 5 ? 'FINISH THE VERSE!' : 'TEMPO INCREASING'}
      </p>
    </div>
  );
};

