            <Mic2 className="text-amber-500/60 animate-pulse hidden xs:block" size={20} />
            <h1 className="heading-font text-4xl sm:text-5xl md:text-7xl font-black tracking-tight gold-gradient-text drop-shadow-2xl gold-glow">
              WORD-TAKSHARI
