            <div className={`${(isTimerActive || isGameOver) ? 'p-3 md:p-4' : 'p-4 md:p-10'} text-center relative border-b border-white/5`}>
              <div className={`flex flex-col items-center justify-center gap-3 md:gap-6 transition-all ${(isTimerActive || isGameOver) ? 'scale-90' : ''}`}>
                <div className="flex flex-wrap items-center justify-center gap-3 md:gap-4 px-4">
                  <h2 className={`${(isTimerActive || isGameOver) ? 'text-3xl md:text-5xl' : 'text-5xl sm:text-6xl md:text-8xl'} hindi-font font-black text-amber-400 gold-glow break-words`}>
                    {selectedWord.word}
                  </h2>
                  <span className={`${(isTimerActive || isGameOver) ? 'text-2xl md:text-4xl' : 'text-4xl sm:text-5xl md:text-6xl'}`}>{selectedWord.emoji}</span>
                </div>

                {!isTimerActive && !isGameOver && !isShowingAnswers && (
                  <div className="space-y-4 md:space-y-6">
                    <div className="space-y-2">
                      <button 
