          </div>
          <div className="flex flex-col items-center leading-none">
            <span className={`text-[7px] md:text-[9px] font-black uppercase tracking-[0.15em] mb-0.5 ${streak > 0 ? 'text-amber-300' : 'text-slate-500'}`}>
