    search: '',
  });

  const [selectedWord, setSelectedWord] = useState<BollywoodWord | null>(null);
  const [isTimerActive, setIsTimerActive] = useState(false);
  const [isShowingAnswers, setIsShowingAnswers] = useState(false);
  const [showRules, setShowRules] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [theme, setTheme] = useState<'luxury' | 'midnight'>('luxury');
  const [roundDuration, setRoundDuration] = useState(15);

  // Streak States
  const [streak, setStreak] = useState(0);
  const [isGameOver, setIsGameOver] = useState(false);
  const [finalStreak, setFinalStreak] = useState(0);

  const [isShuffling, setIsShuffling] = useState(false);
  const [shufflingWord, setShufflingWord] = useState<string>('');
  const [shuffleBlur, setShuffleBlur] = useState(0);

  // Apply theme class to body
  useEffect(() => {
    document.body.className = theme;
  }, [theme]);

  // Resume Audio Context on interaction
  useEffect(() => {
    const initAudio = () => {
      if (gameAudioCtx.state === 'suspended') {
        gameAudioCtx.resume();
      }
      window.removeEventListener('click', initAudio);
      window.removeEventListener('touchstart', initAudio);
    };
    window.addEventListener('click', initAudio);
    window.addEventListener('touchstart', initAudio);
    return () => {
      window.removeEventListener('click', initAudio);
      window.removeEventListener('touchstart', initAudio);
    };
  }, []);

  const { visibleCategories, othersCategories } = useMemo(() => {
    const counts: Record<string, number> = {};
    BOLLYWOOD_WORDS.forEach(w => {
      counts[w.category] = (counts[w.category] || 0) + 1;
    });
    const visible = Object.values(Category).filter(cat => counts[cat] >= 5);
    const others = Object.values(Category).filter(cat => counts[cat] > 0 && counts[cat] < 5);
    return { visibleCategories: visible, othersCategories: others };
  }, []);

  const filteredWords = useMemo(() => {
    return BOLLYWOOD_WORDS.filter((item) => {
      const matchSearch = item.word.toLowerCase().includes(filters.search.toLowerCase()) || 
                          item.englishMeaning.toLowerCase().includes(filters.search.toLowerCase());

      let matchCategory = true;
      if (filters.category === 'All Others') {
        matchCategory = othersCategories.includes(item.category);
      } else if (filters.category !== 'All') {
        matchCategory = item.category === filters.category;
      }

      return matchSearch && matchCategory;
    });
  }, [filters, othersCategories]);

  const handlePickRandom = useCallback(() => {
    if (isShuffling) return;

    setIsShuffling(true);
    setSelectedWord(null);
    setIsTimerActive(false);
    setIsShowingAnswers(false);
    setIsGameOver(false);

    const finalWord = BOLLYWOOD_WORDS[Math.floor(Math.random() * BOLLYWOOD_WORDS.length)];
    let currentIteration = 0;
    const totalIterations = 25;

    const shuffleNext = (delay: number) => {
      currentIteration++;
      const intensity = currentIteration / totalIterations;
      playShuffleTick(intensity);
      const blurAmount = Math.max(0, 10 - (delay / 20));
      setShuffleBlur(blurAmount);

      if (currentIteration >= totalIterations) {
        setShufflingWord(finalWord.word);
        setShuffleBlur(0);
        setTimeout(() => {
          setIsShuffling(false);
          setSelectedWord(finalWord);
          triggerConfetti();
          playStartTune();
        }, 800);
      } else {
        const randomIndex = Math.floor(Math.random() * BOLLYWOOD_WORDS.length);
        setShufflingWord(BOLLYWOOD_WORDS[randomIndex].word);
        const nextDelay = delay * 1.12; 
        setTimeout(() => shuffleNext(nextDelay), nextDelay);
      }
    };
    shuffleNext(40);
  }, [isShuffling]);

  const handleWordClick = (word: BollywoodWord) => {
    setSelectedWord(word);
    setIsTimerActive(false);
    setIsShowingAnswers(false);
    setIsGameOver(false);
    playStartTune();
  };

  const startTimer = () => {
    setIsTimerActive(true);
    setIsShowingAnswers(false);
    setIsGameOver(false);
  };

  const showAnswers = () => {
    setFinalStreak(streak);
    if (streak > 0) {
      setStreak(0);
      playEndTune();
    }
    setIsShowingAnswers(true);
    setIsTimerActive(false);
    setIsGameOver(false);
  };

  const handleVictory = () => {
    triggerConfetti();
    setStreak(prev => prev + 1);
    handlePickRandom();
  };

  const handleDefeat = () => {
    setFinalStreak(streak);
    setStreak(0);
    setIsGameOver(true);
    setIsTimerActive(false);
    playEndTune();
  };

  const handleRestart = () => {
    setStreak(0);
    setIsGameOver(false);
    setIsShowingAnswers(false);
    resetGame();
  };

  const resetGame = () => {
    setSelectedWord(null);
    setIsTimerActive(false);
    setIsShowingAnswers(false);
    setIsGameOver(false);
  };

  const isLuxury = theme === 'luxury';
  const accentColor = isLuxury ? 'emerald-600' : 'teal-500';
  const accentBorder = isLuxury ? 'border-emerald-600' : 'border-teal-500';
  const gradientText = isLuxury ? 'ocean-gradient-text' : 'mint-gradient-text';
  const glowClass = isLuxury ? 'ocean-glow' : 'mint-glow';
  const primaryButtonBg = isLuxury ? 'from-emerald-500 to-cyan-600' : 'from-teal-500 to-blue-600';

  return (
    <div className={`min-h-screen pb-24 px-4 pt-4 md:pt-10 max-w-5xl mx-auto selection:bg-${accentColor}/20`}>

      {/* PERSISTENT STREAK COUNTER */}
      <div className="fixed top-4 right-4 md:top-6 md:right-8 z-[500] pointer-events-none">
        <div 
          key={streak} 
          className={`flex items-center gap-2 md:gap-3 bg-white/90 backdrop-blur-2xl border-2 px-3 py-1.5 md:px-5 md:py-2 rounded-2xl shadow-xl transition-all duration-500 ${
            streak > 0 
              ? `${accentBorder} scale-100 md:scale-110 shadow-emerald-500/10 animate-in zoom-in-95` 
              : 'border-slate-200 opacity-80 scale-90'
          }`}
        >
          <div className="relative">
            <Flame 
              size={18}
              className={`${streak > 0 ? (isLuxury ? 'text-emerald-500' : 'text-teal-400') : 'text-slate-300'} md:w-6 md:h-6 animate-pulse`} 
              fill={streak > 0 ? "currentColor" : "none"} 
            />
          </div>
          <div className="flex flex-col items-center leading-none">
            <span className={`text-[7px] md:text-[9px] font-black uppercase tracking-[0.15em] mb-0.5 ${streak > 0 ? (isLuxury ? 'text-emerald-600' : 'text-teal-600') : 'text-slate-400'}`}>
              Streak
            </span>
            <span className={`text-base md:text-2xl font-black ${streak > 0 ? 'text-slate-900' : 'text-slate-300'}`}>
              {streak}
            </span>
          </div>
        </div>
      </div>

      {/* Header */}
      <header className="mb-10 md:mb-12 text-center mt-8 md:mt-4 px-2">
        <div className="relative inline-flex flex-col items-center max-w-full">
          <div className="flex justify-center items-center gap-2 md:gap-4 mb-2 relative">
            <Mic2 className={`${isLuxury ? 'text-emerald-500/40' : 'text-teal-400/40'} animate-pulse hidden xs:block`} size={18} />
            <h1 className={`heading-font text-3xl sm:text-5xl md:text-7xl font-black tracking-tight ${gradientText} ${glowClass}`}>
              WORD-TAKSHARI
            </h1>
            <Music className={`${isLuxury ? 'text-emerald-500/40' : 'text-teal-400/40'} animate-pulse hidden xs:block`} style={{ animationDelay: '0.5s' }} size={18} />
          </div>
          <p className={`${isLuxury ? 'text-emerald-600/60' : 'text-teal-600/60'} text-[7px] md:text-xs font-bold tracking-[0.2em] md:tracking-[0.5em] uppercase`}>
            The Definitive Bollywood Singing Arena
          </p>
        </div>
      </header>

      {/* Primary Action Button */}
      <div className="flex flex-col sm:flex-row gap-3 md:gap-4 mb-8 md:mb-12">
        <button 
          onClick={handlePickRandom}
          disabled={isShuffling}
          className={`flex-1 relative overflow-hidden group bg-gradient-to-br ${primaryButtonBg} p-6 md:p-8 rounded-2xl md:rounded-3xl shadow-xl hover:shadow-2xl transition-all active:scale-[0.98] disabled:opacity-50 text-white`}
        >
          <div className="relative flex items-center justify-center gap-4 md:gap-5">
             <Shuffle size={24} className={isShuffling ? 'animate-spin' : ''} />
             <div className="text-left">
                <span className="block text-base md:text-2xl font-black heading-font tracking-wide uppercase">RANDOM START</span>
                <span className="block text-[8px] md:text-[10px] uppercase font-bold text-white/60 tracking-widest">Shuffle Melodies</span>
             </div>
          </div>
        </button>

        <button 
          onClick={() => setShowRules(true)}
          className="sm:w-48 bg-white hover:bg-slate-50 p-4 md:p-8 rounded-2xl md:rounded-3xl border border-slate-200 flex flex-col items-center justify-center gap-1 transition-all group shadow-sm"
        >
          <Info className={`text-slate-400 group-hover:${isLuxury ? 'text-emerald-500' : 'text-teal-400'} transition-colors`} size={18} />
          <span className="text-[9px] uppercase font-black tracking-widest text-slate-400 group-hover:text-slate-600">Rules</span>
        </button>
      </div>

      {/* Filters & Search */}
      {!selectedWord && !isShuffling && (
        <section className="animate-in fade-in duration-700">
          <div className="mb-6 md:mb-8 flex flex-col md:flex-row gap-4 items-center glass-panel p-3 md:p-4 rounded-2xl md:rounded-3xl">
            <div className="relative flex-1 w-full">
              <Search className={`absolute left-4 top-1/2 -translate-y-1/2 ${isLuxury ? 'text-emerald-600/40' : 'text-teal-600/40'}`} size={16} />
              <input 
                type="text" 
                placeholder="Search lyrics..."
                value={filters.search}
                onChange={(e) => setFilters(prev => ({ ...prev, search: e.target.value }))}
                className="w-full bg-slate-50 border border-slate-200 text-slate-900 rounded-xl py-3 md:py-4 pl-10 pr-4 focus:outline-none focus:border-emerald-500/40 transition-all placeholder:text-slate-400 text-sm md:text-base"
              />
            </div>
            <div className="flex gap-2 overflow-x-auto pb-1 w-full md:w-auto no-scrollbar scroll-smooth">
              {['All', ...visibleCategories, 'All Others'].map((cat) => (
                <button
                  key={cat}
                  onClick={() => setFilters(prev => ({ ...prev, category: cat as any }))}
                  className={`px-4 md:px-5 py-2 md:py-3 rounded-full text-[8px] md:text-[9px] font-black uppercase tracking-widest border transition-all whitespace-nowrap ${
                    filters.category === cat 
                      ? `${isLuxury ? 'bg-emerald-600 border-emerald-500 text-white' : 'bg-teal-500 border-teal-400 text-white'} shadow-md` 
                      : 'bg-white border-slate-200 text-slate-500 hover:text-slate-800'
                  }`}
                >
                  {cat}
                </button>
              ))}
            </div>
          </div>

          <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-3 md:gap-4">
            {filteredWords.map((item) => (
              <WordCard key={item.id} item={item} onClick={handleWordClick} theme={theme} />
            ))}
          </div>
        </section>
      )}

      {/* Shuffle Animation - Slot Machine Style */}
      {isShuffling && (
        <div className="fixed inset-0 z-[1000] bg-white flex flex-col items-center justify-center p-6 overflow-hidden">
          <div className={`absolute inset-0 opacity-20 pointer-events-none transition-all duration-1000 ${isLuxury ? 'bg-[radial-gradient(circle_at_center,_#10b981_0%,_transparent_70%)]' : 'bg-[radial-gradient(circle_at_center,_#2dd4bf_0%,_transparent_70%)]'} animate-pulse`} />
          <div className="relative z-10 w-full max-w-2xl text-center">
            <p className={`${isLuxury ? 'text-emerald-600' : 'text-teal-600'} font-black tracking-[0.5em] text-[10px] md:text-xs uppercase mb-16 opacity-60 animate-bounce`}>
              Rolling the Melodies...
            </p>
            <div className="perspective-1000 relative h-48 md:h-72 flex items-center justify-center">
               <h2 
                key={shufflingWord}
                style={{ filter: `blur(${shuffleBlur}px)` }}
                className="hindi-font text-6xl md:text-9xl font-black text-slate-900 px-4 leading-tight transition-all duration-75 animate-in slide-in-from-bottom-12"
              >
                {shufflingWord}
              </h2>
            </div>
            <div className="mt-16 flex justify-center gap-4">
               {[1,2,3].map(i => (
                 <div key={i} className={`w-2 h-2 rounded-full ${isLuxury ? 'bg-emerald-500' : 'bg-teal-400'} animate-ping`} style={{ animationDelay: `${i * 0.2}s` }} />
               ))}
            </div>
          </div>
        </div>
      )}

      {/* Detail View Overlay */}
      {selectedWord && !isShuffling && (
        <div className="fixed inset-0 z-[150] bg-white/98 backdrop-blur-xl flex flex-col p-4 animate-in fade-in duration-300 overflow-hidden">
          <div className="flex items-center justify-between w-full h-16 px-2 mb-2 relative z-[160]">
            <button onClick={resetGame} className="text-slate-400 hover:text-slate-900 p-3 transition-colors bg-slate-100 rounded-full border border-slate-200">
              <X size={24} />
            </button>
          </div>

          <div className="flex-1 flex flex-col items-center justify-center overflow-y-auto no-scrollbar pb-10">
            <div className="w-full max-w-xl bg-white border border-slate-100 rounded-[2.5rem] md:rounded-[3rem] overflow-hidden shadow-2xl flex flex-col relative animate-in zoom-in-95 duration-300">
              <div className={`p-6 md:p-10 text-center relative border-b border-slate-100 transition-all ${isTimerActive || isGameOver || isShowingAnswers ? 'pt-10 pb-4' : 'py-10 md:py-16'}`}>
                <div className="flex flex-col items-center justify-center gap-4 md:gap-6">
                  <div className="flex flex-wrap items-center justify-center gap-2 md:gap-4 px-2">
                    <h2 className={`hindi-font font-black ${isLuxury ? 'text-emerald-600' : 'text-teal-600'} break-words transition-all ${isTimerActive || isGameOver || isShowingAnswers ? 'text-4xl md:text-6xl' : 'text-5xl md:text-8xl'}`}>
                      {selectedWord.word}
                    </h2>
                    <span className={`transition-all ${isTimerActive || isGameOver || isShowingAnswers ? 'text-3xl md:text-5xl' : 'text-4xl md:text-7xl'}`}>{selectedWord.emoji}</span>
                  </div>

                  {!isTimerActive && !isGameOver && !isShowingAnswers && (
                    <div className="space-y-4 md:space-y-6 animate-in fade-in slide-in-from-bottom-4 text-center">
                      <p className="text-slate-500 text-base md:text-xl font-medium tracking-tight italic px-4">
                        "{selectedWord.englishMeaning}"
                      </p>
                      <div className={`bg-${accentColor}/5 border border-${accentColor}/10 rounded-2xl p-4 md:p-6 shadow-sm max-w-xs mx-auto`}>
                         <p className={`${isLuxury ? 'text-emerald-600' : 'text-teal-600'} text-[9px] font-black uppercase tracking-widest mb-1`}>Target</p>
                         <p className="text-slate-800 text-xs md:text-sm font-bold">Sing a song with <span className={isLuxury ? 'text-emerald-600' : 'text-teal-600'}>"{selectedWord.word}"</span></p>
                      </div>
                    </div>
                  )}
                </div>
              </div>

              <div className="p-6 md:p-10 flex-1">
                {!isTimerActive && !isShowingAnswers && !isGameOver && (
                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 py-2 max-w-sm mx-auto">
                    <button 
                      onClick={startTimer}
                      className={`flex flex-col items-center justify-center gap-2 bg-gradient-to-br ${primaryButtonBg} text-white font-black py-6 md:py-8 rounded-2xl md:rounded-3xl shadow-xl hover:brightness-110 active:scale-[0.98] transition-all`}
                    >
                      <TimerIcon size={24} />
                      <span className="text-sm heading-font tracking-widest">SING NOW</span>
                    </button>
                    <button onClick={showAnswers} className="flex flex-col items-center justify-center gap-2 bg-slate-50 hover:bg-slate-100 text-slate-500 font-bold py-6 md:py-8 rounded-2xl md:rounded-3xl border border-slate-200 transition-all active:scale-[0.98]">
                      <Eye size={24} />
                      <span className="text-sm heading-font tracking-widest uppercase">Reveal Hints</span>
                    </button>
                  </div>
                )}

                {isTimerActive && !isShowingAnswers && !isGameOver && (
                  <div className="flex flex-col items-center justify-center space-y-6 md:space-y-12">
                    <div className="scale-90 md:scale-110">
                      <Timer duration={roundDuration} onComplete={handleDefeat} onTick={(left) => playTickSound(left)} isActive={true} theme={theme} />
                    </div>
                    <div className="w-full space-y-6 max-w-sm mx-auto">
                      <div className="flex gap-4 h-20 md:h-24 px-2">
                        <button onClick={handleVictory} className="flex-1 bg-emerald-600 hover:bg-emerald-500 text-white font-black rounded-2xl shadow-lg flex flex-col items-center justify-center gap-1 transition-all active:translate-y-1">
                          <CheckCircle size={22} />
                          <span className="text-[10px] md:text-xs uppercase tracking-wide">NAILED IT</span>
                        </button>
                        <button onClick={handleDefeat} className="flex-1 bg-slate-100 text-slate-500 font-bold rounded-2xl border border-slate-200 flex flex-col items-center justify-center gap-1 transition-all active:scale-95">
                          <HelpCircle size={22} className={isLuxury ? 'text-emerald-500' : 'text-teal-400'} />
                          <span className="text-[10px] md:text-xs uppercase tracking-wide">NO IDEA</span>
                        </button>
                      </div>
                    </div>
                  </div>
                )}

                {isGameOver && (
                  <div className="flex flex-col items-center justify-center py-4 md:py-8 animate-in zoom-in-95">
                    <div className="relative mb-6">
                      <div className={`bg-gradient-to-br ${primaryButtonBg} p-8 rounded-full shadow-xl`}>
                        <Trophy size={48} className="text-white" />
                      </div>
                    </div>
                    <h3 className="heading-font text-2xl md:text-4xl font-black text-slate-900 mb-2 uppercase tracking-tighter">FINALE</h3>
                    <div className="flex items-center gap-3 mb-8">
                      <span className="text-slate-400 font-black text-xl tracking-widest uppercase">STREAK:</span>
                      <span className={`${isLuxury ? 'text-emerald-600' : 'text-teal-600'} font-black text-5xl`}>{finalStreak}</span>
                    </div>
                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 w-full max-w-sm mx-auto">
                      <button onClick={handleRestart} className="bg-slate-100 hover:bg-slate-200 text-slate-600 font-black py-4 rounded-xl border border-slate-200 transition-all active:scale-95 text-xs tracking-widest uppercase">REPLAY</button>
                      <button onClick={() => { setIsGameOver(false); setIsShowingAnswers(true); }} className={`bg-${accentColor} hover:brightness-110 text-white font-black py-4 rounded-xl shadow-lg transition-all active:scale-95 text-xs tracking-widest uppercase`}>LYRICS</button>
                    </div>
                  </div>
                )}

                {isShowingAnswers && !isGameOver && (
                  <div className="space-y-6 animate-in slide-in-from-bottom-6 max-w-sm mx-auto">
                    <div className="bg-slate-50 border border-slate-100 rounded-2xl p-4 text-center">
                      <p className="text-slate-400 font-black uppercase text-[10px] tracking-widest mb-1">Result</p>
                      <p className="text-slate-900 font-bold text-lg">Score: {finalStreak}</p>
                    </div>
                    <div className="space-y-3">
                      {selectedWord.songs.map((song, i) => (
                        <div key={i} className="bg-white p-4 rounded-2xl border border-slate-100 flex items-center justify-between group shadow-sm">
                          <div className="flex-1 pr-3">
                            <p className={`font-bold text-sm leading-tight mb-1 ${isLuxury ? 'text-emerald-700' : 'text-teal-700'}`}>{song.title}</p>
                            <p className="text-slate-500 text-[10px] italic line-clamp-1">"{song.lyrics}"</p>
                          </div>
                          <a href={`https://www.youtube.com/results?search_query=${encodeURIComponent(song.title)}`} target="_blank" rel="noopener noreferrer" className={`w-10 h-10 rounded-full ${isLuxury ? 'bg-emerald-50 text-emerald-600' : 'bg-teal-50 text-teal-500'} flex items-center justify-center hover:bg-emerald-100 transition-all active:scale-90`}>
                            <Play size={14} fill="currentColor" />
                          </a>
                        </div>
                      ))}
                    </div>
                    <button onClick={handleRestart} className="w-full bg-slate-100 hover:bg-slate-200 text-slate-600 font-black py-4 rounded-xl flex items-center justify-center gap-3 text-[10px] tracking-widest uppercase transition-all">
                      <Home size={16} /> MAIN SCREEN
                    </button>
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>
      )}

      {/* SETTINGS BUTTON (BOTTOM RIGHT) */}
      <div className="fixed bottom-6 right-6 z-[500]">
        <button 
          onClick={() => setShowSettings(true)}
          className={`flex items-center justify-center w-14 h-14 bg-white shadow-2xl rounded-full border border-slate-200 transition-all hover:scale-110 active:scale-95 ${isLuxury ? 'text-emerald-600' : 'text-teal-500'}`}
        >
          <Settings size={24} />
        </button>
      </div>

      {/* SETTINGS OVERLAY */}
      {showSettings && (
        <div className="fixed inset-0 z-[600] flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-sm animate-in fade-in duration-300">
          <div className="w-full max-w-sm bg-white border border-slate-200 rounded-[2.5rem] p-8 shadow-2xl relative overflow-hidden">
            <button onClick={() => setShowSettings(false)} className="absolute right-6 top-6 text-slate-400 hover:text-slate-900 transition-colors">
              <X size={24} />
            </button>

            <h2 className="heading-font text-2xl font-black text-slate-900 mb-8 tracking-widest uppercase flex items-center gap-3">
              <Settings className={isLuxury ? 'text-emerald-600' : 'text-teal-500'} size={24} />
              Settings
            </h2>

            <div className="space-y-8">
              {/* Theme Selection */}
              <div className="space-y-4">
                <label className="text-[10px] font-black uppercase tracking-widest text-slate-400 block">Atmosphere</label>
                <div className="grid grid-cols-2 gap-3">
                  <button 
                    onClick={() => setTheme('luxury')}
                    className={`flex items-center justify-center gap-2 p-4 rounded-2xl border-2 transition-all ${isLuxury ? 'border-emerald-500 bg-emerald-50 text-emerald-900' : 'border-slate-100 bg-slate-50 text-slate-400'}`}
                  >
                    <Sun size={18} />
                    <span className="text-xs font-bold">Luminous</span>
                  </button>
                  <button 
                    onClick={() => setTheme('midnight')}
                    className={`flex items-center justify-center gap-2 p-4 rounded-2xl border-2 transition-all ${!isLuxury ? 'border-teal-500 bg-teal-50 text-teal-900' : 'border-slate-100 bg-slate-50 text-slate-400'}`}
                  >
                    <Moon size={18} />
                    <span className="text-xs font-bold">Midnight</span>
                  </button>
                </div>
              </div>

              {/* Timer Selection */}
              <div className="space-y-4">
                <label className="text-[10px] font-black uppercase tracking-widest text-slate-400 block">Singing Duration</label>
                <div className="grid grid-cols-4 gap-2">
                  {[5, 10, 15, 30].map((t) => (
                    <button 
                      key={t}
                      onClick={() => setRoundDuration(t)}
                      className={`flex flex-col items-center justify-center p-3 rounded-xl border-2 transition-all ${roundDuration === t ? (isLuxury ? 'border-emerald-500 bg-emerald-50 text-emerald-900' : 'border-teal-500 bg-teal-50 text-teal-900') : 'border-slate-100 bg-slate-50 text-slate-400'}`}
                    >
                      <span className="text-sm font-black">{t}s</span>
                    </button>
                  ))}
                </div>
              </div>
            </div>

            <button 
              onClick={() => setShowSettings(false)} 
              className={`w-full mt-10 ${isLuxury ? 'bg-emerald-600' : 'bg-teal-500'} text-white font-black py-4 rounded-xl shadow-lg transition-all active:scale-95 uppercase tracking-widest text-xs`}
            >
