          </div>
        </div>
      )}

      {showRules && (
        <div className="fixed inset-0 z-[600] bg-white/95 flex items-center justify-center p-4 backdrop-blur-md">
          <div className="w-full max-w-md bg-white border border-slate-200 rounded-[2.5rem] p-8 relative shadow-2xl overflow-y-auto max-h-[90vh]">
            <button onClick={() => setShowRules(false)} className="absolute right-6 top-6 text-slate-400 hover:text-slate-900 p-2 transition-colors"><X size={24} /></button>
            <h2 className={`heading-font text-3xl font-black ${isLuxury ? 'text-emerald-600' : 'text-teal-600'} mb-8 tracking-widest uppercase`}>RULES</h2>
            <div className="space-y-6 text-slate-600 font-medium leading-relaxed text-sm">
              <p>I. Select a Bollywood keyword to start.</p>
              <p>II. You have <span className={isLuxury ? 'text-emerald-600 font-bold' : 'text-teal-600 font-bold'}>{roundDuration} seconds</span> to sing a song with that word.</p>
              <p>III. <span className="font-bold">GIVING UP</span> shows lyrics but resets your streak.</p>
              <p>IV. <span className="text-emerald-600 font-bold">STREAKS:</span> Keep singing without help to build your score!</p>
            </div>
            <button onClick={() => setShowRules(false)} className={`w-full mt-10 ${isLuxury ? 'bg-emerald-600' : 'bg-teal-500'} text-white font-black py-4 rounded-xl shadow-lg hover:brightness-110 active:translate-y-1 transition-all uppercase tracking-widest text-sm`}>LET'S GO</button>
          </div>
        </div>
      )}
    </div>
  );
};

