            <div className="flex flex-col items-center leading-none">
              <span className={`text-[7px] md:text-[9px] font-black uppercase tracking-[0.15em] mb-0.5 ${streak > 0 ? (isLuxury ? 'text-emerald-600' : 'text-teal-400') : 'text-slate-400'}`}>
